import asyncio
from collections import defaultdict

class GameState:
    def __init__(self):
        self.players = {}

    def add_player(self, player_id, position):
        self.players[player_id] = position

    def remove_player(self, player_id):
        if player_id in self.players:
            del self.players[player_id]

    def get_full_state(self):
        return {"players": self.players}

class GameServer:
    def __init__(self):
        self.clients = defaultdict(set)
        self.game_state = GameState()

    async def handle_client(self, reader, writer):
        while True:
            try:
                data = await reader.read(1024)
                if not data:
                    break
                message = data.decode()
                player_id, *position = message.split(',')
                position = tuple(map(float, position))
                self.game_state.add_player(player_id, position)

                state = self.game_state.get_full_state()
                writer.write((f"{player_id},{','.join(str(p) for p in position)}").encode())
                await writer.drain()

            except Exception as e:
                print(f"Error: {e}")
                break

        writer.close()
        await writer.wait_closed()

    async def broadcast(self):
        while True:
            state = self.game_state.get_full_state()
            for player_id, connections in self.clients.items():
                for conn in connections:
                    try:
                        conn.write((f"{player_id},{','.join(str(p) for p in position)}").encode())
                        await conn.drain()
                    except Exception as e:
                        print(f"Error broadcasting to {player_id}: {e}")
            await asyncio.sleep(1)

    async def start_server(self):
        server = await asyncio.start_server(self.handle_client, 'localhost', 8888)
        addr = server.sockets[0].getsockname()
        print(f'Serving on {addr}')

        tasks = [asyncio.create_task(server.serve_forever()), asyncio.create_task(self.broadcast())]
        await asyncio.gather(*tasks)

if __name__ == "__main__":
    game_server = GameServer()
    asyncio.run(game_server.start_server())